#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long *A = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &A[i]);
        long long ans = 0;
        for (int i = 0; i < N; ++i) {
            for (int j = i + 1; j < N; ++j) {
                long long diffIdx = j - i;
                long long diffVal = llabs(A[i] - A[j]);
                long long w = diffIdx < diffVal ? diffIdx : diffVal;
                if (w > ans) ans = w;
            }
        }
        printf("%lld\n", ans);
        free(A);
    }
    return 0;
}

